%% DC Motor Speed Control Using PI + Lead Controller
% Author: Hussein Issa
% Description:
% This script models a DC motor, designs the final PI + Lead controller,
% and verifies the system using step response, tracking, disturbance,
% and robustness analysis.

clc
clear
close all

s = tf('s');

%% 1. Motor Parameters
R  = 1;
L  = 0.5;
J  = 0.01;
b  = 0.01;
Kt = 0.1;
Ke = 0.1;

%% 2. Plant Transfer Function
Gv = Kt/(L*J*s^2 + (L*b + R*J)*s + (R*b + Ke*Kt));

%% 3. Open-Loop Analysis
figure %[output:42fdba7d]
step(Gv) %[output:42fdba7d]
grid on %[output:42fdba7d]
title('Open-Loop Step Response') %[output:42fdba7d]
xlabel('Time (s)') %[output:42fdba7d]
ylabel('Angular Speed (rad/s)') %[output:42fdba7d]

open_loop_info = stepinfo(Gv) %[output:342aabc2]
open_loop_poles = pole(Gv) %[output:2cc9974f]

%% 4. Final PI + Lead Controller
K = 4.9307;
z1 = 2.5;
z2 = 2;
p  = 27.99;

C = K*(s+z1)*(s+z2)/(s*(s+p));

%% 5. Closed-Loop Verification
T = feedback(C*Gv,1);

figure %[output:78e32137]
step(T) %[output:78e32137]
grid on %[output:78e32137]
title('Closed-Loop Unit-Step Response') %[output:78e32137]
xlabel('Time (s)') %[output:78e32137]
ylabel('Angular Speed (rad/s)') %[output:78e32137]

closed_loop_info = stepinfo(T) %[output:18c15cf2]
closed_loop_poles = pole(T) %[output:3a5139c4]

%% 6. Controller Output for Unit-Step Reference
U = feedback(C,C*Gv);

figure %[output:5510b0fe]
step(U) %[output:5510b0fe]
grid on %[output:5510b0fe]
title('Controller Output for Unit-Step Reference') %[output:5510b0fe]
xlabel('Time (s)') %[output:5510b0fe]
ylabel('Control Voltage (V)') %[output:5510b0fe]

%% 7. Tracking of Time-Varying Reference
t = (0:0.01:60)';   % column vector

ref = zeros(size(t));

for i = 1:length(t)
    if t(i) < 10
        ref(i) = 40;
    else
        ref(i) = 40 + 5*sin(0.5*(t(i)-10));
    end
end

[y,t_out] = lsim(T, ref, t);

%% Plot
figure %[output:67d3c2fc]
plot(t_out, ref, '--', 'LineWidth', 1.5) %[output:67d3c2fc]
hold on %[output:67d3c2fc]
plot(t_out, y, 'LineWidth', 1.5) %[output:67d3c2fc]
grid on %[output:67d3c2fc]
legend('Reference','Motor Speed','Location','best') %[output:67d3c2fc]
title('Tracking Response for Time-Varying Reference') %[output:67d3c2fc]
xlabel('Time (s)') %[output:67d3c2fc]
ylabel('Angular Speed (rad/s)') %[output:67d3c2fc]

%% Tracking error after sinusoidal tracking begins
idx = t_out >= 12;   % ignore startup and switching transient

tracking_error = ref(idx) - y(idx);

max_tracking_error = max(abs(tracking_error));
rmse_tracking_error = sqrt(mean(tracking_error.^2));

fprintf('Maximum tracking error = %.3f rad/s\n', max_tracking_error); %[output:3be87be3]
fprintf('RMS tracking error = %.3f rad/s\n', rmse_tracking_error); %[output:9c65c8a7]

%% 8. Disturbance Transfer Function
Gd = -(L*s + R)/(L*J*s^2 + (L*b + R*J)*s + (R*b + Ke*Kt));

% Closed-loop disturbance-to-output transfer function
Td = Gd/(1 + C*Gv);

figure %[output:432fe309]
step(0.1*Td) %[output:432fe309]
grid on %[output:432fe309]
title('Closed-Loop Response to 0.1 N.m Load Disturbance') %[output:432fe309]
xlabel('Time (s)') %[output:432fe309]
ylabel('Speed Deviation (rad/s)') %[output:432fe309]

%% 9. Robustness Analysis

% J increased by 20%
J_var = 1.2*J;
Gv_J = Kt/(L*J_var*s^2 + (L*b + R*J_var)*s + (R*b + Ke*Kt));
T_J = feedback(C*Gv_J,1);

% b increased by 50%
b_var = 1.5*b;
Gv_b = Kt/(L*J*s^2 + (L*b_var + R*J)*s + (R*b_var + Ke*Kt));
T_b = feedback(C*Gv_b,1);

% Kt decreased by 20%
Kt_var = 0.8*Kt;
Gv_Kt = Kt_var/(L*J*s^2 + (L*b + R*J)*s + (R*b + Ke*Kt_var));
T_Kt = feedback(C*Gv_Kt,1);

% R increased by 20%
R_var = 1.2*R;
Gv_R = Kt/(L*J*s^2 + (L*b + R_var*J)*s + (R_var*b + Ke*Kt));
T_R = feedback(C*Gv_R,1);

figure %[output:384f5d16]
systems = {T_J, T_b, T_Kt, T_R};
titles = {'J = 1.2J', 'b = 1.5b', 'K_t = 0.8K_t', 'R = 1.2R'};

for k = 1:4 %[output:group:626e932f]
    subplot(2,2,k) %[output:384f5d16]
    step(systems{k})
    grid on
    title(titles{k})
    xlabel('Time (s)')
    ylabel('Speed (rad/s)')
    xlim([0 5])
    ylim([0 1.15])
end %[output:group:626e932f]

